export class HlmTFoot {
	private readonly _globalOrDefaultConfig = injectHlmTableConfig();
	constructor() {
		classes(() => (this._globalOrDefaultConfig ? this._globalOrDefaultConfig.tfoot.trim() : ''));
	}
